import { useEffect, useMemo, useState } from "react";
import { cn } from "../lib/utils";

export default function SideNav({ sections }) {
  const [active, setActive] = useState(sections[0]?.id ?? null);

  const ids = useMemo(() => sections.map((s) => s.id), [sections]);

  useEffect(() => {
    const elements = ids
      .map((id) => document.getElementById(id))
      .filter((el) => Boolean(el));

    if (elements.length === 0) return;

    const handleInitial = () => {
      const byTop = [...elements].sort((a, b) => Math.abs(a.getBoundingClientRect().top) - Math.abs(b.getBoundingClientRect().top))[0];
      if (byTop?.id) setActive(byTop.id);
    };

    handleInitial();

    const observer = new IntersectionObserver(
      (entries) => {
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio)[0];
        if (visible?.target && visible.target.id) {
          setActive(visible.target.id);
        }
      },
      {
        root: null,
        rootMargin: "-45% 0px -45% 0px",
        threshold: [0.2, 0.4, 0.6, 1, 1],
      }
    );

    elements.forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, [ids]);

  const onClick = (id) => (e) => {
    e.preventDefault();
    const el = document.getElementById(id);
    if (!el) return;
    el.scrollIntoView({ behavior: "smooth", block: "start" });
    setActive(id);
  };

  return (
    <nav
      aria-label="Secciones"
      className="hidden md:flex fixed left-0 top-20 bottom-0 z-40 w-auto min-w-[200px] max-w-[280px] px-3"
    >
      <div className="h-full rounded-r-2xl border border-white/40 bg-white/60 backdrop-blur-xl shadow-lg supports-[backdrop-filter]:bg-white/50 p-3 flex-1">
        <ul className="flex flex-col gap-1.5">
          {sections.map((s) => {
            const isActive = active === s.id;
            return (
              <li key={s.id} className="flex">
                <a 
                  href={`#${s.id}`} 
                  onClick={onClick(s.id)} 
                  className="group block flex-1"
                >
                  <div
                    className={cn(
                      "rounded-xl p-[1.5px] transition-all w-full",
                      isActive
                        ? "bg-gradient-to-r from-[#072D42] via-[#F29E38] to-[#072D42] bg-[length:200%_200%] animate-gradient-x shadow-[0_0_0_4px_rgba(7,45,66,0.06)]"
                        : "bg-transparent group-hover:bg-gradient-to-r group-hover:from-[#072D42] group-hover:via-[#F29E38] group-hover:to-[#072D42] group-hover:bg-[length:200%_200%] group-hover:animate-gradient-x group-hover:shadow-[0_0_0_6px_rgba(242,158,56,0.10)]"
                    )}
                  >
                    <div
                      className={cn(
                        "rounded-[10px] px-4 py-2 transition-all w-full",
                        isActive ? "bg-white ring-1 ring-[#072D42]/15" : "bg-white/80 group-hover:bg-white shadow-sm"
                      )}
                    >
                      <span className="relative inline-flex items-center gap-2 w-full">
                        <span
                          className={cn(
                            "font-medium text-sm flex-1",
                            isActive
                              ? "bg-gradient-to-r from-[#072D42] via-[#F29E38] to-[#072D42] bg-[length:200%_200%] animate-gradient-x bg-clip-text text-transparent"
                              : "text-brand-dark/80 group-hover:text-brand-dark"
                          )}
                        >
                          {s.label}
                        </span>
                        <span
                          aria-hidden
                          className={cn(
                            "absolute -bottom-1 left-0 h-0.5 rounded-full transition-all",
                            isActive
                              ? "w-full bg-gradient-to-r from-[#072D42] via-[#F29E38] to-[#072D42] bg-[length:200%_200%] animate-gradient-x"
                              : "w-0 bg-[#F29E38] group-hover:w-full"
                          )}
                        />
                      </span>
                    </div>
                  </div>
                </a>
              </li>
            );
          })}
        </ul>
      </div>
    </nav>
  );
}
